194→export function createInitialAppState(): VaultAppState {
195→  const categories: Category[] = defaultCategorySeeds.map((seed, index) => ({
196→    uid: seed.slug,
197→    name: seed.title,
198→    emoji: seed.emoji,
199→    sortOrder: index,
200→    colorHex: seed.pastelHex,
201→    isPlanSuppressed: false,
202→    planSuppressedAt: null,
203→    planSuppressedReason: null,
204→    items: [],
205→  }));
206→
207→  return {
208→    schemaVersion: 1,
209→    user: {
210→      id: createId('user'),
211→      name: 'Default User',
212→    },
213→    vault: {
214→      uid: createId('vault'),
215→      categories,
216→      carts: [],
217→      stores: [],
218→      deletedItems: [],
219→      deletedCarts: [],
220→      deletedCartItemSnapshots: [],
221→    },
222→    preferences: {
223→      hasCompletedOnboarding: false,
224→      userName: '',
225→      hasPromptedForNameAfterOnboarding: false,
226→      hasPromptedForNameAfterVaultCelebration: false,
227→      hasShownAddItemGuideAfterName: false,
228→      isPro: false,
229→      freeEditableStoreKeys: [],
230→      freePrimaryEditableCartId: null,
231→    },
232→  };
233→}
