235→export function cloneState<T>(value: T): T {
236→  return JSON.parse(JSON.stringify(value)) as T;
237→}
238→
239→export function getCategoryById(vault: Vault, categoryId: string): Category | undefined {
240→  return vault.categories.find(category => category.uid === categoryId);
241→}
242→
243→export function getItemById(vault: Vault, itemId: string): Item | undefined {
244→  for (const category of vault.categories) {
245→    const match = category.items.find(item => item.id === itemId);
246→    if (match) {
247→      return match;
248→    }
249→  }
250→
251→  return vault.deletedItems.find(item => item.id === itemId);
252→}
253→
254→export function getCurrentPrice(item: Item, store: string): number | null {
255→  return item.priceOptions.find(option => option.store === store)?.pricePerUnit.priceValue ?? null;
256→}
257→
258→export function getCurrentUnit(item: Item, store: string): string | null {
259→  return item.priceOptions.find(option => option.store === store)?.pricePerUnit.unit ?? null;
260→}
261→
262→export function createCartItemFromVaultItem(
263→  vault: Vault,
264→  itemId: string,
265→  quantity: number,
266→  selectedStore?: string | null
267→): CartItem {
268→  const item = getItemById(vault, itemId);
269→  if (!item) {
270→    throw new Error(`Item ${itemId} not found`);
271→  }
272→
273→  const plannedStore = selectedStore ?? item.priceOptions[0]?.store ?? vault.stores[0]?.name ?? 'Unknown Store';
274→
275→  return {
276→    id: createId('cartItem'),
277→    addedAt: new Date().toISOString(),
278→    itemId,
279→    quantity,
280→    isFulfilled: false,
281→    isSkippedDuringShopping: false,
282→    plannedStore,
283→    plannedPrice: getCurrentPrice(item, plannedStore),
284→    plannedUnit: getCurrentUnit(item, plannedStore),
285→    actualStore: null,
286→    actualPrice: null,
287→    actualQuantity: null,
288→    actualUnit: null,
289→    wasEditedDuringShopping: false,
290→    isShoppingOnlyItem: false,
291→    shoppingOnlyName: null,
292→    shoppingOnlyStore: null,
293→    shoppingOnlyPrice: null,
294→    shoppingOnlyUnit: null,
295→    shoppingOnlyCategory: null,
296→    vaultItemNameSnapshot: item.name,
297→    vaultItemCategorySnapshot: getCategoryById(vault, item.categoryId)?.name ?? null,
298→    originalPlanningQuantity: null,
299→    addedDuringShopping: false,
300→    fulfillmentAnimationState: 0,
301→    fulfillmentStartTime: null,
302→    shouldShowCheckmark: false,
303→    shouldStrikethrough: false,
304→    isOnSale: false,
305→    notes: null,
306→    saleType: null,
307→    discountValue: null,
308→    regularPrice: null,
309→  };
310→}
311→
312→export function computeCartTotal(vault: Vault, cart: Cart): number {
313→  return cart.cartItems.reduce((total, cartItem) => {
314→    if (cart.status !== 'planning' && cartItem.isSkippedDuringShopping) {
315→      return total;
316→    }
317→
318→    const item = getItemById(vault, cartItem.itemId);
319→    const fallbackPrice = item ? getCurrentPrice(item, cartItem.plannedStore) ?? 0 : 0;
320→    const price =
321→      cart.status !== 'planning'
322→        ? cartItem.actualPrice ?? cartItem.plannedPrice ?? fallbackPrice
323→        : cartItem.plannedPrice ?? fallbackPrice;
324→
325→    const quantity = cart.status === 'planning'
326→      ? cartItem.quantity
327→      : cartItem.actualQuantity ?? cartItem.quantity;
328→
329→    return total + price * quantity;
330→  }, 0);
331→}
332→
333→export function computeDashboardSummary(state: VaultAppState): DashboardSummary {
334→  const activeCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status !== 'completed');
335→  const completedCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status === 'completed');
336→  const cartTotals = completedCarts.map(cart => ({ cart, total: computeCartTotal(state.vault, cart) }));
337→  const totalSpent = cartTotals.reduce((sum, entry) => sum + entry.total, 0);
338→  const overBudgetCount = cartTotals.filter(entry => entry.total > entry.cart.budget).length;
339→  const itemCount = state.vault.categories.reduce((sum, category) => sum + category.items.length, 0);
340→
341→  return {
342→    activeCarts,
343→    completedCarts,
344→    totalSpent,
345→    overBudgetCount,
346→    itemCount,
347→  };
348→}
349→
350→export function completeOnboardingState(
351→  baseState: VaultAppState,
352→  input: CompleteOnboardingInput
353→): VaultAppState {
354→  const state = baseState;
355→  const normalizedName = input.userName.trim();
356→  const normalizedStore = input.primaryStore.trim();
357→  const normalizedItemName = input.firstItemName.trim();
358→  const normalizedUnit = input.firstItemUnit.trim();
359→  const category = getCategoryById(state.vault, input.firstCategoryId);
360→
361→  if (!category) {
362→    throw new Error('Selected category was not found.');
363→  }
364→
365→  state.user.name = normalizedName;
366→  state.preferences.userName = normalizedName;
367→  state.preferences.hasCompletedOnboarding = true;
368→
369→  const existingStore = state.vault.stores.find(store => store.name.toLowerCase() === normalizedStore.toLowerCase());
370→  const store = existingStore ?? {
371→    id: createId('store'),
372→    name: normalizedStore,
373→    createdAt: new Date().toISOString(),
374→  };
375→
376→  if (!existingStore) {
377→    state.vault.stores.push(store);
378→  }
379→
380→  category.items.unshift({
381→    id: createId('item'),
382→    name: normalizedItemName,
383→    categoryId: category.uid,
384→    priceOptions: [
385→      {
386→        id: createId('priceOption'),
387→        store: store.name,
388→        pricePerUnit: {
389→          priceValue: input.firstItemPrice,
390→          unit: normalizedUnit,
391→        },
392→      },
393→    ],
394→    createdAt: new Date().toISOString(),
395→    isTemporaryShoppingItem: false,
396→    shoppingPrice: null,
397→    shoppingUnit: null,
398→    isOnSale: false,
399→    notes: null,
400→    saleType: null,
401→    discountValue: null,
402→    regularPrice: null,
403→    isDeleted: false,
404→    deletedAt: null,
405→    deletedFromCategoryName: null,
406→    isPlanSuppressed: false,
407→    planSuppressedAt: null,
408→    planSuppressedReason: null,
409→  });
410→
411→  return state;
412→}
