  4→import { emptySubscriptionSnapshot, subscriptionService, SubscriptionSnapshot } from '../services/subscriptionService';
  5→import { appRepository } from '../storage/repository';
  6→
  7→type DraftSelections = Record<string, number>;
  8→
  9→interface AppStoreState {
 10→  isBootstrapping: boolean;
 11→  errorMessage: string | null;
 12→  appState: VaultAppState | null;
 13→  draftSelections: DraftSelections;
 14→  subscription: SubscriptionSnapshot;
 15→  bootstrap: () => Promise<void>;
 16→  refresh: () => Promise<void>;
 17→  completeOnboarding: (input: CompleteOnboardingInput) => Promise<void>;
 18→  updateUserName: (name: string) => Promise<void>;
 19→  addCategory: (name: string, emoji: string) => Promise<void>;
 20→  addItem: (input: AddItemInput) => Promise<void>;
 21→  createCart: (input: CreateCartInput) => Promise<void>;
 22→  toggleCartItemFulfillment: (cartId: string, cartItemId: string) => Promise<void>;
 23→  advanceCartStatus: (cartId: string) => Promise<void>;
 24→  toggleDraftItem: (itemId: string) => void;
 25→  setDraftQuantity: (itemId: string, quantity: number) => void;
 26→  clearDraftSelections: () => void;
 27→  resetApp: () => Promise<void>;
 28→}
 29→
 30→async function refreshSubscription(
 31→  set: (partial: Partial<AppStoreState>) => void,
 32→  current: SubscriptionSnapshot
 33→): Promise<SubscriptionSnapshot> {
 34→  const loading = { ...current, isLoading: true };
 35→  set({ subscription: loading });
 36→  const next = await subscriptionService.refresh(loading);
 37→  set({ subscription: next });
 38→  return next;
 39→}
 40→
 41→export const useAppStore = create<AppStoreState>((set, get) => ({
 42→  isBootstrapping: true,
 43→  errorMessage: null,
 44→  appState: null,
 45→  draftSelections: {},
 46→  subscription: emptySubscriptionSnapshot,
 47→
 48→  bootstrap: async () => {
 49→    try {
 50→      set({ isBootstrapping: true, errorMessage: null });
 51→      const appState = await appRepository.loadState();
 52→      set({ appState, isBootstrapping: false });
 53→      await refreshSubscription(set, get().subscription);
 54→    } catch (error) {
 55→      set({
 56→        isBootstrapping: false,
 57→        errorMessage: error instanceof Error ? error.message : 'Failed to bootstrap Grock.',
 58→      });
 59→    }
 60→  },
 61→
 62→  refresh: async () => {
 63→    try {
 64→      const appState = await appRepository.loadState();
 65→      set({ appState, errorMessage: null });
 66→      await refreshSubscription(set, get().subscription);
 67→    } catch (error) {
 68→      set({ errorMessage: error instanceof Error ? error.message : 'Refresh failed.' });
 69→    }
 70→  },
 71→
 72→  completeOnboarding: async input => {
 73→    const appState = await appRepository.completeOnboarding(input);
 74→    set({ appState, errorMessage: null });
 75→  },
 76→
 77→  updateUserName: async name => {
 78→    const appState = await appRepository.updateUserName(name);
 79→    set({ appState, errorMessage: null });
 80→  },
 81→
 82→  addCategory: async (name, emoji) => {
 83→    const appState = await appRepository.addCategory(name, emoji);
 84→    set({ appState, errorMessage: null });
 85→  },
 86→
 87→  addItem: async input => {
 88→    const appState = await appRepository.addItem(input);
 89→    set({ appState, errorMessage: null });
 90→  },
 91→
 92→  createCart: async input => {
 93→    const appState = await appRepository.createCart(input);
 94→    set({ appState, errorMessage: null, draftSelections: {} });
 95→  },
 96→
 97→  toggleCartItemFulfillment: async (cartId, cartItemId) => {
 98→    const appState = await appRepository.toggleCartItemFulfillment(cartId, cartItemId);
 99→    set({ appState, errorMessage: null });
100→  },
101→
102→  advanceCartStatus: async cartId => {
103→    const appState = await appRepository.advanceCartStatus(cartId);
104→    set({ appState, errorMessage: null });
105→  },
106→
107→  toggleDraftItem: itemId => {
108→    const current = get().draftSelections;
109→    if (current[itemId]) {
110→      const next = { ...current };
111→      delete next[itemId];
112→      set({ draftSelections: next });
113→      return;
114→    }
115→
116→    set({ draftSelections: { ...current, [itemId]: 1 } });
117→  },
118→
119→  setDraftQuantity: (itemId, quantity) => {
120→    const safeQuantity = Math.max(1, quantity);
121→    set({
122→      draftSelections: {
123→        ...get().draftSelections,
124→        [itemId]: safeQuantity,
125→      },
126→    });
127→  },
128→
129→  clearDraftSelections: () => set({ draftSelections: {} }),
130→
131→  resetApp: async () => {
132→    const appState = await appRepository.resetState();
133→    set({
134→      appState,
135→      draftSelections: {},
136→      errorMessage: null,
137→    });
138→  },
139→}));
